import React, { useState, useEffect } from "react";
import bookingService from "../services/bookingService";
import { useAuth } from "../context/AuthContext";
import { useToast } from "../components/Toast";
import "./Bookings.css"; // ✅ CSS import

export default function Bookings() {
  const { user } = useAuth();
  const showToast = useToast();

  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);

  const [selectedBooking, setSelectedBooking] = useState(null);
  const [selectedSeats, setSelectedSeats] = useState([]);

  const load = () => {
    if (!user) return;

    bookingService
      .getByUser(user.id)
      .then(setBookings)
      .catch(() => showToast("Error loading bookings", "error"))
      .finally(() => setLoading(false));
  };

  useEffect(() => {
    load();
  }, [user]);

  const cancelBooking = async (id) => {
    if (!window.confirm("Cancel full booking?")) return;

    await bookingService.cancel(id);
    showToast("Booking cancelled", "success");
    load();
  };

  const openCancelModal = (booking) => {
    setSelectedBooking(booking);
    setSelectedSeats([]);
  };

  const toggleSeat = (seatId) => {
    setSelectedSeats((prev) =>
      prev.includes(seatId)
        ? prev.filter((id) => id !== seatId)
        : [...prev, seatId],
    );
  };

  const confirmCancel = async () => {
    if (selectedSeats.length === 0) {
      showToast("Select at least one seat", "error");
      return;
    }

    try {
      await bookingService.partialCancel(
        selectedBooking.bookingId,
        selectedSeats,
      );

      showToast("Seats cancelled", "success");
      setSelectedBooking(null);
      load();
    } catch {
      showToast("Cancel failed", "error");
    }
  };

  return (
    <div className="container">
      <h2 className="title">🎟️ My Bookings</h2>

      {loading ? (
        <p>Loading...</p>
      ) : bookings.length === 0 ? (
        <p>No bookings</p>
      ) : (
        bookings.map((b) => (
          <div key={b.bookingId} className="booking-card">
            <h3>🎬 {b.movieTitle}</h3>

            <p>
              🏛️ {b.theaterName} — {b.screenName}
            </p>
            <p>💺 {b.seats?.map((s) => s.seatNumber).join(", ")}</p>
            <p>💰 ₹{b.totalPrice}</p>
            <p
              className={
                b.bookingStatus === "CONFIRMED" ? "status-ok" : "status-cancel"
              }
            >
              {b.bookingStatus}
            </p>

            {b.bookingStatus === "CONFIRMED" && (
              <div className="actions">
                <button
                  className="btn cancel-full"
                  onClick={() => cancelBooking(b.bookingId)}
                >
                  Cancel Full
                </button>

                <button
                  className="btn cancel-seat"
                  onClick={() => openCancelModal(b)}
                >
                  Cancel Seats
                </button>
              </div>
            )}
          </div>
        ))
      )}

      {/* 🔥 MODAL */}
      {selectedBooking && (
        <div className="overlay">
          <div className="modal">
            <h3>Select Seats to Cancel</h3>

            <div className="seat-grid">
              {selectedBooking.seats.map((seat) => (
                <div
                  key={seat.id}
                  className={`seat-box ${
                    selectedSeats.includes(seat.id) ? "selected" : ""
                  }`}
                  onClick={() => toggleSeat(seat.id)}
                >
                  {seat.seatNumber}
                </div>
              ))}
            </div>

            <div className="modal-actions">
              <button className="btn confirm" onClick={confirmCancel}>
                Confirm Cancel
              </button>

              <button
                className="btn close"
                onClick={() => setSelectedBooking(null)}
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
